import fs from "fs";
import { NextRequest, NextResponse } from "next/server";
import formidable from "formidable";
import { promisify } from "util";
import { writeFile } from "fs/promises";

export const config = {
  api: { bodyParser: false },
};

async function parseForm(req: NextRequest) {
  const form = formidable({ keepExtensions: true });

  return new Promise((resolve, reject) => {
    form.parse(req, (err, fields, files) => {
      if (err) reject(err);
      else resolve({ fields, files });
    });
  });
}

export async function POST(req: NextRequest) {
  try {
    const buffer = await req.arrayBuffer();
    const filePath = "./public/uploads/uploaded.pdf";
    await writeFile(filePath, Buffer.from(buffer));

    console.log("File saved:", filePath);

    // Read file as Base64
    const base64File = fs.readFileSync(filePath, { encoding: "base64" });

    // 🔹 Send File to OCR.space API
    const ocrResponse = await fetch("https://api.ocr.space/parse/image", {
      method: "POST",
      headers: {
        apikey: "794bb1dbf588957", // Replace with your actual key
        "Content-Type": "application/x-www-form-urlencoded",
      },
      body: new URLSearchParams({
        base64image: `data:application/pdf;base64,${base64File}`,
        isOverlayRequired: "true",
        language: "eng",
      }),
    });

    const result = await ocrResponse.json();
    console.log("OCR API Response:", JSON.stringify(result, null, 2));

    if (!result || !result.ParsedResults) {
      return NextResponse.json({ error: "OCR API failed" }, { status: 500 });
    }

    const extractedText = result.ParsedResults[0]?.ParsedText || "";
    const isMarksheet =
      /\b(subjects?|marks?\b(?!.*total)|percentage|grade|score|cgpa|gpa)\b/i.test(
        extractedText
      );

    return NextResponse.json(
      { text: extractedText, isMarksheet },
      { status: 200 }
    );
  } catch (error) {
    console.error("Error processing file:", error);
    return NextResponse.json(
      { error: "Error processing file" },
      { status: 500 }
    );
  }
}
